(function(){const e=document.documentElement,t=document.getElementById("theme-toggle"),n=localStorage.getItem("theme");n&&e.setAttribute("data-theme",n),t?.addEventListener("click",()=>{const s=e.getAttribute("data-theme"),n=s==="light"?"dark":"light";e.setAttribute("data-theme",n),localStorage.setItem("theme",n),t.textContent=n==="light"?"🌙 Dark":"☀️ Light"});const s=document.querySelectorAll(".toc-sidebar nav a");if(!s.length)return;const o=[...document.querySelectorAll(".post-content h2, .post-content h3, .post-content h4")],i=new IntersectionObserver(e=>{e.forEach(e=>{if(e.isIntersecting){s.forEach(e=>e.classList.remove("active"));const t=document.querySelector(`.toc-sidebar nav a[href="#${e.target.id}"]`);t?.classList.add("active")}})},{rootMargin:"-20% 0px -75% 0px"});o.forEach(e=>i.observe(e))})()